import { useState } from 'react';
import FixturesArray from '../../components/data/fixtures'
import ResultsRow from './resultsrow'

const ResultsGrid = () => {

    const  [fixtures, setFixture] = useState(FixturesArray);

    return(
        <>            
            <table className="table table-hover">
                <thead>
                    <tr>
                        <th>Date</th>
                        <th>Result</th>
                        <th>Home Team</th>
                        <th>H Score</th>
                        <th>A Score</th>
                        <th>Away Team</th>
                        <th>Type</th>
                    </tr>
                </thead>
                <tbody>
                    {Fixtures.map(f => <ResultsRow key={f.id} fixture={f}/>)}
                </tbody>
            </table>  
        </>
    );
}
export default ResultsGrid;
